graphql.query:
query fetchGlobalData {
    fetchGlobalData {
        loginPageContent {
            posLogo
            heading
            subHeading
            footerContent
            footerNote
        }
        locales {
            code
            name
            direction
        }
        currencies {
            code
            name
            symbol
        }
        countries {
            id
            code
            name
        }
        countryStates {
            countryCode
            states {
                id
                countryId
                countryCode
                code
                defaultName
            }
        }
    }
}

mutation agentLogout {
    agentLogout {
        success
        message
    }
}

mutation deletePosCustomer ($id: ID!) {
    deletePosCustomer(id: $id) {
        success
        message
    }
}

query getOutletProducts {
    getOutletProducts (
        page: 1
        first: 10
    ) {
        paginatorInfo {
            count
            currentPage
            lastPage
            total
        }
        data {
            id
            sku
            type
            name
            quantity
            price
            barcode
            priceHtml
            images {
                id
                url
            }
            categories {
                id
                name
                parentId
                children {
                    id
                    name
                    parentId
                }
            }
            variantConfigurations
            downloadableSamples {
                id
                url
                file
                fileName
                fileUrl
                type
                sortOrder
                productId
                createdAt
                updatedAt
                translations {
                    id
                    locale
                    title
                    productDownloadableSampleId
                }
            }
            downloadableLinks {
                id
                title
                price
                url
                file
                fileUrl
                fileName
                type
                sampleUrl
                sampleFile
                sampleFileName
                sampleFileUrl
                sampleType
                sortOrder
                productId
                downloads
                translations {
                    id
                    locale
                    title
                    productDownloadableLinkId
                }
            }
            groupedProducts {
                id
                qty
                sortOrder
                productId
                associatedProductId
                associatedProduct {
                    id
                    type
                    name
                    attributeFamilyId
                    sku
                    parentId
                    isSaleable
                    priceHtml {
                        minPrice
                        priceHtml
                    }
                }
            }
            options {
                id
                label
                type
                isRequired
                sortOrder
                products {
                    id
                    qty
                    name
                    productId
                    isDefault
                    sortOrder
                    inStock
                    inventory
                    price {
                        regular {
                            price
                            formattedPrice
                        }
                        final {
                            price
                            formattedPrice
                        }
                    }
                }
            }
        }
    }
}

query getOutletCategories {
    getOutletCategories (
        page: 1
        first: 10
    ) {
        paginatorInfo {
            count
            currentPage
            lastPage
            total
        }
        data {
            id
            slug
            name
            parentId
            children {
                id
                slug
                name
                parentId
                children {
                    id
                    slug
                    name
                    parentId
                }
            }
        }
    }
}

query getOrders {
    getOrders(
        page: 1
        first: 10
    ) {
        paginatorInfo {
            count
            currentPage
            lastPage
            total
        }
        data {
            outlet {
                name
                agent {
                    email
                    firstName
                    lastName
                }
            }
            customerCredit {
                changeAmount
                tenderedAmount
            }
            order {
                id
                customerFirstName
                customerLastName
                customerEmail
                totalQtyOrdered
                discountAmount
                taxAmount
                subTotal
                grandTotal
                createdAt
                customer {
                    name
                    phone
                }
                formattedPrice {
                    discountAmount
                    taxAmount
                    subTotal
                    grandTotal
                }
                items {
                    sku
                    name
                    qtyOrdered
                    price
                    baseTotal
                    additional
                    formattedPrice {
                        price
                        baseTotal
                    }
                }
            }
        }
    }
}

query getDrawerDetails {
    getDrawerDetails {
        openingAmount
        cashPaymentSale
        otherPaymentSale
        expectedDrawerAmount
        differenceAmount
        remark
    }
}

mutation openDrawer (
    $input: drawerInput!
) {
    openDrawer (
        input: $input
    ) {
        success
        errors
        message
    }
}

mutation closeDrawer (
    $input: drawerInput!
) {
    closeDrawer (
        input: $input
    ) {
        success
        errors
        message
    }
}

query getTodaySales {
    getTodaySales (
        orderId: 22
        time: "2024-07-30 09:38:00"
        orderTotal: 200
        paymentMode: "pos_cash"
    ) {
        openingAmount
        cashPaymentSale
        otherPaymentSale
        orders {
            orderId
            orderTotal
            paymentMode
            createdAt
        }
    }
}

query getSaleHistory {
    getSaleHistory (
        date: ""
        cashPayment: 0
        otherPayment: 0
        totalSale: 0
    ) {
        createdAt
        cashPayment
        otherPayment
        totalSale
        drawerNote
    }
}

query getSaleReport (
    $startDate: String
    $endDate: String
) {
    getSaleReport (
        startDate: $startDate
        endDate: $endDate
    ) {
        reports {
            ordersCount {
                name
                total
                progress
                goingUp
                series {
                    name
                    data
                }
                labels
            }
            avgOrderValue {
                name
                total
                progress
                goingUp
                series {
                    name
                    data
                }
                labels
            }
            avgItemsPerOrder {
                name
                total
                progress
                goingUp
                series {
                    name
                    data
                }
                labels
            }
            discountOffers {
                name
                total
                progress
                goingUp
                series {
                    name
                    data
                }
                labels
            }
            cashPayments {
                name
                total
                progress
                goingUp
                series {
                    name
                    data
                }
                labels
            }
            otherPayments {
                name
                total
                progress
                goingUp
                series {
                    name
                    data
                }
                labels
            }
        }
    }
}

mutation getLowStockProducts (
    $minQty: Int!
) {
    getLowStockProducts (
        minQty: $minQty
    ) {
        id
        sku
        type
        name
        quantity
        price
        priceHtml
        images {
            id
            url
        }
    }
}

mutation requestProductQty (
    $input: requestProductQtyInput!
) {
    requestProductQty (
        input: $input
    ) {
        success
        message
    }
}

mutation createOutletProduct (
    $input: createOutletProductInput!
) {
    createOutletProduct (
        input: $input
    ) {
        success
        errors
        message
    }
}

query getRequestedProducts($query: String!) {
    getRequestedProducts(query: $query) {
        id
        name
        comment
        requestedQuantity
        requestStatus
        requestedDate
        createdAt
        updatedAt
    }
}

mutation syncOrder (
    $input: syncOrderInput!
) {
    syncOrder (
        input: $input
    ) {
        success
        message
    }
}
